+        let f = FrankenSqliteBackend::open_in_memory().unwrap();
+        let stmts: &[&str] = &[
+            "CREATE TABLE t (id INTEGER PRIMARY KEY, val TEXT, num REAL)",
+            "INSERT INTO t VALUES (1, 'alpha', 1.5)",
+            "INSERT INTO t VALUES (2, 'beta', 2.5)",
+            "INSERT INTO t VALUES (3, 'gamma', 3.5)",
